/**
 * Design System breakpoints.
 *
 * CSS media queries use the same numeric values:
 *   mobile:    @media (max-width: 600px)
 *   tablet:    @media (max-width: 1023px)
 *   desktop-s: @media (max-width: 1279px)
 */
export declare const BREAKPOINT_MOBILE = 600;
export declare const BREAKPOINT_TABLET = 1023;
export declare const BREAKPOINT_DESKTOP_S = 1279;
